#include <bits/stdc++.h>
using namespace std;
const int maxn=4e1;
long long n,sum,t,dp[maxn*maxn];
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	sum=n*(n+1)/2;
	if(sum&1) {
		cout<<0;
		return 0;
	}
	sum/=2;
	dp[0]=1;
	for(int i=1; i<=n; i++) for(int j=sum; j>=0; j--) dp[j]+=dp[j-i];
	cout<<dp[sum]/2;
	return 0;
}
